import{_ as a,o as r,c as o,a2 as l}from"./chunks/framework.Bjylvv1V.js";const u=JSON.parse('{"title":"예산 편성","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/budget.md","filePath":"guide/scenarios/budget.md","lastUpdated":null}'),e={name:"guide/scenarios/budget.md"};function s(n,t,i,h,d,c){return r(),o("div",null,[...t[0]||(t[0]=[l(`<h1 id="예산-편성" tabindex="-1">예산 편성 <a class="header-anchor" href="#예산-편성" aria-label="Permalink to &quot;예산 편성&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 약 2시간 | <strong>난이도</strong>: ★★★ | <strong>주기</strong>: 연 1회 (12월~1월)</p></blockquote><p>다음 연도 단지 운영에 필요한 수입·지출 예산을 계정과목별로 편성하고, 입주자대표회의 의결을 거쳐 시스템에 확정 등록하는 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 전년 실적 분석         (20분) → 예산실적대조표로 전년 집행 검토</span></span>
<span class="line"><span>2. 예산안 작성            (60분) → 계정과목별 금액 입력 및 월별 배분</span></span>
<span class="line"><span>3. 입주자대표회의 의결     (외부)  → 예산안 확정 (시스템 외 절차)</span></span>
<span class="line"><span>4. 예산 확정 등록         (10분) → 의결된 예산 저장</span></span>
<span class="line"><span>5. 추경예산 등록          (10분) → 변경 사항 발생 시에만 처리</span></span>
<span class="line"><span>6. 예산집행현황 모니터링   (5분)  → 월별 집행 현황 수시 확인</span></span>
<span class="line"><span>7. 예산서/예산실적대조표 출력 (5분) → 관리·보고용 출력</span></span></code></pre></div><hr><h2 id="사전-확인" tabindex="-1">사전 확인 <a class="header-anchor" href="#사전-확인" aria-label="Permalink to &quot;사전 확인&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">예산 편성 시기</p><p>통상 <strong>12월 초~1월 중</strong>에 다음 연도 예산을 편성합니다. 관리규약에서 정한 일정을 먼저 확인하세요.</p></div><h3 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h3><ul><li>[ ] 당해 연도 예산실적대조표를 검토했는가?</li><li>[ ] 전년 대비 변동 예정 항목(인건비 인상, 용역 계약 갱신 등)을 파악했는가?</li><li>[ ] 관리규약상 예산 편성 기준과 입주자대표회의 의결 일정을 확인했는가?</li><li>[ ] 세입·세출 계정과목 코드가 최신 상태인가?</li></ul><hr><h2 id="_1단계-전년-실적-분석-20분" tabindex="-1">1단계: 전년 실적 분석 (20분) <a class="header-anchor" href="#_1단계-전년-실적-분석-20분" aria-label="Permalink to &quot;1단계: 전년 실적 분석 (20분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/budget.html">예산관리</a> &gt; 예산실적대조표 (ACCT6050)</p></blockquote><p>전년도 예산 대비 실제 집행 현황을 확인하여 다음 연도 예산 수립의 근거로 활용합니다.</p><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>예산실적대조표 화면 진입</li><li><strong>조회 연도</strong> 선택 (전년도)</li><li><strong>세입</strong> / <strong>세출</strong> 구분 선택 후 조회</li><li>항목별 <strong>예산액 vs 실적액 vs 증감</strong> 확인</li></ol><h3 id="확인-포인트" tabindex="-1">확인 포인트 <a class="header-anchor" href="#확인-포인트" aria-label="Permalink to &quot;확인 포인트&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>확인 내용</th></tr></thead><tbody><tr><td><strong>집행률이 낮은 항목</strong></td><td>과다 편성 여부 → 감액 검토</td></tr><tr><td><strong>예산 초과 항목</strong></td><td>부족 원인 파악 → 증액 검토</td></tr><tr><td><strong>신규 지출 예정 항목</strong></td><td>전년 미편성 항목 신규 추가</td></tr></tbody></table><hr><h2 id="_2단계-예산안-작성-60분" tabindex="-1">2단계: 예산안 작성 (60분) <a class="header-anchor" href="#_2단계-예산안-작성-60분" aria-label="Permalink to &quot;2단계: 예산안 작성 (60분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/budget.html">예산관리</a> &gt; 예산등록 (ACCT6010)</p></blockquote><p>계정과목별 연간 예산 금액을 입력합니다.</p><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>예산등록 화면 진입</li><li><strong>년이월</strong> 선택 → 등록할 연도 입력</li><li><strong>조회</strong> 클릭 → 전년도 계정과목 목록 불러오기</li><li><strong>세입</strong> / <strong>세출</strong> 탭을 전환하며 각 계정과목 금액 입력</li><li>금액 입력 후 <strong>저장</strong> 클릭</li></ol><h3 id="월별-배분-방법" tabindex="-1">월별 배분 방법 <a class="header-anchor" href="#월별-배분-방법" aria-label="Permalink to &quot;월별 배분 방법&quot;">​</a></h3><p>계정과목 행을 <strong>더블클릭</strong>하면 12개월 월별 배분 팝업이 열립니다.</p><table tabindex="0"><thead><tr><th>배분 방식</th><th>설명</th></tr></thead><tbody><tr><td><strong>자동 균등 배분</strong></td><td>연간 금액 ÷ 12 → 각 월에 동일 배분</td></tr><tr><td><strong>수동 입력</strong></td><td>계절성 지출(냉·난방 등)은 월별로 직접 입력</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">계절성 항목 예시</p><p>난방비(11~3월), 냉방비(6~9월), 청소 특별소독비(하절기) 등은 월별 수동 배분이 권장됩니다.</p></div><h3 id="세입·세출-구분" tabindex="-1">세입·세출 구분 <a class="header-anchor" href="#세입·세출-구분" aria-label="Permalink to &quot;세입·세출 구분&quot;">​</a></h3><table tabindex="0"><thead><tr><th>구분</th><th>설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>세입</strong></td><td>단지로 들어오는 수입</td><td>관리비 수입, 이자 수입, 잡수입</td></tr><tr><td><strong>세출</strong></td><td>단지에서 나가는 지출</td><td>인건비, 용역비, 수선유지비, 보험료</td></tr></tbody></table><hr><h2 id="_3단계-입주자대표회의-의결-외부-절차" tabindex="-1">3단계: 입주자대표회의 의결 (외부 절차) <a class="header-anchor" href="#_3단계-입주자대표회의-의결-외부-절차" aria-label="Permalink to &quot;3단계: 입주자대표회의 의결 (외부 절차)&quot;">​</a></h2><p>예산안을 관리규약에 따라 <strong>입주자대표회의에 제출·의결</strong>합니다. 이 단계는 시스템 외부 절차입니다.</p><ul><li>예산서 출력: 회계 &gt; <a href="/acct/budget.html">예산관리</a> &gt; 예산서 (ACCT6040)</li><li>의결이 완료된 후 4단계를 진행합니다.</li></ul><div class="warning custom-block"><p class="custom-block-title">의결 전 확정 금지</p><p>입주자대표회의 의결 전에 예산을 확정하지 마세요. 의결된 내용과 시스템 내 금액이 반드시 일치해야 합니다.</p></div><hr><h2 id="_4단계-예산-확정-등록-10분" tabindex="-1">4단계: 예산 확정 등록 (10분) <a class="header-anchor" href="#_4단계-예산-확정-등록-10분" aria-label="Permalink to &quot;4단계: 예산 확정 등록 (10분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/budget.html">예산관리</a> &gt; 예산등록 (ACCT6010)</p></blockquote><p>의결된 예산을 최종 저장하여 집행 기준으로 확정합니다.</p><h3 id="절차-2" tabindex="-1">절차 <a class="header-anchor" href="#절차-2" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>예산등록 화면에서 해당 연도 조회</li><li>의결 내용에 맞게 금액 수정 (변경 사항이 있는 경우)</li><li><strong>저장</strong> 클릭</li><li>예산서(ACCT6040)를 출력하여 의결 내용과 최종 대조 확인</li></ol><hr><h2 id="_5단계-추경예산-등록-필요-시-10분" tabindex="-1">5단계: 추경예산 등록 (필요 시, 10분) <a class="header-anchor" href="#_5단계-추경예산-등록-필요-시-10분" aria-label="Permalink to &quot;5단계: 추경예산 등록 (필요 시, 10분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/budget.html">예산관리</a> &gt; 추경예산등록 (ACCT6011)</p></blockquote><p>연중 예산 확정 후 불가피한 사정으로 <strong>예산을 변경</strong>해야 할 때만 사용합니다.</p><h3 id="언제-사용하나" tabindex="-1">언제 사용하나? <a class="header-anchor" href="#언제-사용하나" aria-label="Permalink to &quot;언제 사용하나?&quot;">​</a></h3><ul><li>예상치 못한 대규모 시설 수선 발생</li><li>관리비 단가 변경으로 세입 구조 변화</li><li>입주자대표회의에서 예산 변경 의결</li></ul><h3 id="절차-3" tabindex="-1">절차 <a class="header-anchor" href="#절차-3" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>추경예산등록 화면 진입</li><li>해당 연도·회차 선택 (1차 추경, 2차 추경 등)</li><li>변경 항목 금액 수정 후 <strong>저장</strong></li></ol><div class="warning custom-block"><p class="custom-block-title">추경은 꼭 필요할 때만</p><p>추경예산은 예산 확정 후 변경이 필요한 경우에만 사용합니다. 일상적인 소액 변동은 예산 조정이 아닌 집행 단계에서 관리합니다.</p></div><hr><h2 id="_6단계-예산집행현황-모니터링-5분" tabindex="-1">6단계: 예산집행현황 모니터링 (5분) <a class="header-anchor" href="#_6단계-예산집행현황-모니터링-5분" aria-label="Permalink to &quot;6단계: 예산집행현황 모니터링 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/budget.html">예산관리</a> &gt; 예산집행현황 (ACCT6020)</p></blockquote><p>월별로 예산 대비 집행 잔여 현황을 확인합니다.</p><h3 id="절차-4" tabindex="-1">절차 <a class="header-anchor" href="#절차-4" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>예산집행현황 화면 진입</li><li><strong>조회 기간</strong> 선택 (월별 또는 누계)</li><li><strong>세입</strong> / <strong>세출</strong> 구분 선택 후 조회</li><li>항목별 <strong>예산액 / 집행액 / 잔액 / 집행률</strong> 확인</li></ol><h3 id="확인-포인트-1" tabindex="-1">확인 포인트 <a class="header-anchor" href="#확인-포인트-1" aria-label="Permalink to &quot;확인 포인트&quot;">​</a></h3><ul><li>[ ] 집행률이 지나치게 낮은 항목(예산 미집행 위험)은 없는가?</li><li>[ ] 예산 잔액이 부족하여 초과 지출 위험이 있는 항목은 없는가?</li></ul><div class="tip custom-block"><p class="custom-block-title">수시 모니터링 권장</p><p>예산집행현황은 매월 말 마감 전에 확인하는 것이 좋습니다. 예산 초과가 예상되면 추경예산 절차를 조기에 진행하세요.</p></div><hr><h2 id="_7단계-예산서-예산실적대조표-출력-5분" tabindex="-1">7단계: 예산서/예산실적대조표 출력 (5분) <a class="header-anchor" href="#_7단계-예산서-예산실적대조표-출력-5분" aria-label="Permalink to &quot;7단계: 예산서/예산실적대조표 출력 (5분)&quot;">​</a></h2><h3 id="예산서" tabindex="-1">예산서 <a class="header-anchor" href="#예산서" aria-label="Permalink to &quot;예산서&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/budget.html">예산관리</a> &gt; 예산서 (ACCT6040)</p></blockquote><p>연간 세입·세출 예산을 보고용으로 출력합니다.</p><h3 id="예산결산서" tabindex="-1">예산결산서 <a class="header-anchor" href="#예산결산서" aria-label="Permalink to &quot;예산결산서&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/budget.html">예산관리</a> &gt; 예산결산서 (ACCT6030)</p></blockquote><p>연도말 결산 후 예산 대비 결산 현황을 출력합니다.</p><h3 id="예산실적대조표" tabindex="-1">예산실적대조표 <a class="header-anchor" href="#예산실적대조표" aria-label="Permalink to &quot;예산실적대조표&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/budget.html">예산관리</a> &gt; 예산실적대조표 (ACCT6050)</p></blockquote><p>전기 예산 vs 실제 집행 증감을 비교하는 표입니다. 다음 연도 예산 편성 시 필수 참고 자료입니다.</p><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="예산등록-화면에서-전년도-계정과목이-안-나와요" tabindex="-1">예산등록 화면에서 전년도 계정과목이 안 나와요 <a class="header-anchor" href="#예산등록-화면에서-전년도-계정과목이-안-나와요" aria-label="Permalink to &quot;예산등록 화면에서 전년도 계정과목이 안 나와요&quot;">​</a></h3><p><strong>원인</strong>: 년이월 후 조회를 하지 않았거나, 전년도 예산이 등록되지 않은 상태입니다. <strong>해결</strong>: 년이월 항목을 올바르게 선택한 후 <strong>조회</strong> 버튼을 클릭하세요. 최초 연도 설정이라면 계정과목을 직접 추가해야 합니다.</p><h3 id="월별-배분-더블클릭이-작동하지-않아요" tabindex="-1">월별 배분 더블클릭이 작동하지 않아요 <a class="header-anchor" href="#월별-배분-더블클릭이-작동하지-않아요" aria-label="Permalink to &quot;월별 배분 더블클릭이 작동하지 않아요&quot;">​</a></h3><p><strong>원인</strong>: 계정과목 행이 아닌 금액 셀이나 다른 영역을 클릭한 경우입니다. <strong>해결</strong>: 계정과목 코드 또는 항목명이 있는 <strong>행의 왼쪽 영역</strong>을 더블클릭하세요.</p><h3 id="예산-초과-지출이-발생했어요" tabindex="-1">예산 초과 지출이 발생했어요 <a class="header-anchor" href="#예산-초과-지출이-발생했어요" aria-label="Permalink to &quot;예산 초과 지출이 발생했어요&quot;">​</a></h3><p><strong>원인</strong>: 예산 편성 시 미반영된 지출이 발생했거나 집행 관리가 미흡한 경우입니다. <strong>해결</strong>: 입주자대표회의 의결을 거쳐 추경예산(ACCT6011)으로 예산을 증액하세요. 의결 없이 예산 초과 지출은 관리규약 위반이 될 수 있습니다.</p><h3 id="세입과-세출-합계가-맞지-않아요" tabindex="-1">세입과 세출 합계가 맞지 않아요 <a class="header-anchor" href="#세입과-세출-합계가-맞지-않아요" aria-label="Permalink to &quot;세입과 세출 합계가 맞지 않아요&quot;">​</a></h3><p><strong>원인</strong>: 관리비 수입과 지출 예산이 일치하지 않는 경우입니다. <strong>해결</strong>: 예산 편성 원칙상 세입과 세출은 균형을 이루어야 합니다. 항목별로 재검토하여 누락된 세입 또는 세출 항목이 있는지 확인하세요.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/acct/budget.html">예산등록</a> - 연간 예산 입력 및 확정 (ACCT6010)</li><li><a href="/acct/budget.html">추경예산등록</a> - 예산 변경 처리 (ACCT6011)</li><li><a href="/acct/budget.html">예산집행현황</a> - 집행 현황 모니터링 (ACCT6020)</li><li><a href="/acct/budget.html">예산결산서</a> - 결산 후 예산 대비 결과 출력 (ACCT6030)</li><li><a href="/acct/budget.html">예산서</a> - 보고용 예산 문서 출력 (ACCT6040)</li><li><a href="/acct/budget.html">예산실적대조표</a> - 전기 대비 증감 비교 (ACCT6050)</li><li><a href="/guide/scenarios/year-end.html">연말 결산</a> - 결산 후 예산실적 확인</li></ul>`,83)])])}const b=a(e,[["render",s]]);export{u as __pageData,b as default};
